var e=`/api/signers`;async function t(e,t={}){let n=await fetch(e,{...t,credentials:`include`,headers:{"Content-Type":`application/json`,...t.headers},signal:t.signal});if(!n.ok){let e=await n.json().catch(()=>({error:`Request failed`}));throw Error(e.error||`HTTP ${n.status}`)}return n.json()}var n={list:n=>t(e,{signal:n}),listByCompany:(n,r,i)=>t(`${e}?company_id=${n}&company_type=${r}`,{signal:i}),getById:(n,r)=>t(`${e}/${n}`,{signal:r}),create:(n,r)=>t(e,{method:`POST`,body:JSON.stringify(n),signal:r}),update:(n,r,i)=>t(`${e}/${n}`,{method:`PUT`,body:JSON.stringify(r),signal:i}),delete:(n,r)=>t(`${e}/${n}`,{method:`DELETE`,signal:r})};export{n as t};